  1	import React, { FC, memo, useState } from 'react';
  2	
  3	import {
  4	  Button,
  5	  ButtonVariant,
  6	  Checkbox,
  7	  ExpandableSectionToggle,
  8	  List,
  9	  ListItem,
 10	  Tooltip,
 11	} from '@patternfly/react-core';
 12	import { LongArrowAltDownIcon, LongArrowAltUpIcon } from '@patternfly/react-icons';
 13	import { Td, Tr } from '@patternfly/react-table';
 14	import { NodeNetworkConfigurationInterface, V1beta1NodeNetworkState } from '@types';
 15	import { getPorts } from '@utils/interfaces/getters';
 16	
 17	import useDrawerInterface from '../hooks/useDrawerInterface';
 18	
 19	import './interfaces-table.scss';
 20	
 21	interface InterfacesTypeSectionProps {
 22	  interfaces: NodeNetworkConfigurationInterface[];
 23	  interfaceType: string;
 24	  nodeNetworkState: V1beta1NodeNetworkState;
 25	  expandAll: boolean;
 26	}
 27	
 28	const InterfacesTypeSection: FC<InterfacesTypeSectionProps> = memo(
 29	  ({ interfaceType, interfaces, nodeNetworkState, expandAll }) => {
 30	    const [expand, setExpand] = useState(false);
 31	
 32	    const { setSelectedInterfaceName } = useDrawerInterface();
 33	
 34	    const isExpanded = expandAll || expand;
 35	    return (
 36	      <>
 37	        <Tr className="interfaces-table__interface-type-row">
 38	          <Td colSpan={6}>
 39	            <ExpandableSectionToggle
 40	              isExpanded={isExpanded}
 41	              onToggle={setExpand}
 42	              className="expandable-section-interface-type"
 43	              data-test={`${interfaceType}-expandable-section-toggle`}
 44	            >
 45	              {interfaceType}
 46	            </ExpandableSectionToggle>
 47	          </Td>
 48	        </Tr>
 49	
 50	        {interfaces.map((iface) => {
 51	          const address = iface.ipv4?.address || iface.ipv6?.address;
 52	          const ports = getPorts(iface);
 53	          const Icon =
 54	            iface.state.toLowerCase() === 'up' ? LongArrowAltUpIcon : LongArrowAltDownIcon;
 55	
 56	          return (
 57	            <Tr
 58	              key={iface.name}
 59	              isExpanded={isExpanded}
 60	              className="interfaces-table__interfaces-expandable-row"
 61	            >
 62	              <Td className="interfaces-table__interfaces-expandable-row__column-name">
 63	                <Button
 64	                  variant={ButtonVariant.link}
 65	                  onClick={() => setSelectedInterfaceName(nodeNetworkState, iface)}
 66	                  data-test={`${interfaceType}-${iface.name}-open-drawer`}
 67	                >
 68	                  {iface.name}
 69	                  <Icon className="interfaces-table__interfaces-expandable-row__status-icon" />
 70	                </Button>
 71	              </Td>
 72	              <Td>
 73	                {address?.[0] ? (
 74	                  <>
 75	                    {address?.[0]?.ip}/{address?.[0]?.['prefix-length']}
 76	                  </>
 77	                ) : (
 78	                  '-'
 79	                )}
 80	              </Td>
 81	              <Td>
 82	                {ports?.length ? (
 83	                  <Tooltip
 84	                    content={
 85	                      <List isPlain>
 86	                        {ports.map((port) => (
 87	                          <ListItem key={port}>{port}</ListItem>
 88	                        ))}
 89	                      </List>
 90	                    }
 91	                  >
 92	                    <span>{ports.length}</span>
 93	                  </Tooltip>
 94	                ) : (
 95	                  '-'
 96	                )}
 97	              </Td>
 98	              <Td>{iface?.['mac-address'] || '-'}</Td>
 99	              <Td>
100	                <Checkbox
101	                  id={`lldp-enabled-${interfaceType}-${iface.name}`}
102	                  isDisabled
103	                  isChecked={iface.lldp?.enabled}
104	                />
105	              </Td>
106	              <Td>{iface?.mtu || '-'}</Td>
107	            </Tr>
108	          );
109	        })}
110	      </>
111	    );
112	  },
113	);
114	
115	InterfacesTypeSection.displayName = 'InterfacesTypeSection';
116	
117	export default InterfacesTypeSection;

